// Récupérer les données du webhook
const items = $input.all();
const item = items[0]?.json || {};
const requestBody = item.body || item;

// Récupérer les paramètres
const network = requestBody.target || requestBody.network;
const emailTo = requestBody.email || requestBody.emailTo;
const portRange = requestBody.ports || requestBody.portRange || '22,80,443';

if (!network) {
    throw new Error('Cible manquante. Utilisez "target" dans votre requête');
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const scanId = `scan_${timestamp}`;

console.log('========================================');
console.log('📥 Scan request received:');
console.log(`   Network: ${network}`);
console.log(`   Email: ${emailTo}`);
console.log(`   Ports: ${portRange}`);
console.log(`   ScanId: ${scanId}`);
console.log('========================================');

const fs = require('fs');
const tempDir = '/tmp/vulnscan';
if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

const requestFile = `${tempDir}/request_${scanId}.json`;
fs.writeFileSync(requestFile, JSON.stringify({
    scanId, network, emailTo, portRange, timestamp,
    status: 'running',
    createdAt: new Date().toISOString()
}, null, 2));

return [{
  json: {
    network, emailTo, portRange, timestamp, scanId, tempDir
  }
}];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const network = data.network;
const scanId = data.scanId;
const portRange = data.portRange;
const tempDir = data.tempDir;

console.log('🔍 Nmap scan starting...');
console.log(`   Network: ${network}`);
console.log(`   Ports: ${portRange}`);

if (!network) {
    return [{ json: { stdout: '<?xml version="1.0"?><nmaprun></nmaprun>', error: 'No target', success: false } }];
}

try {
    const cmd = `nmap -sV --open -p ${portRange} -T4 -oX - ${network} 2>/dev/null`;
    console.log(`CMD: ${cmd}`);

    let stdout = '';
    try {
        stdout = execSync(cmd, { encoding: 'utf-8', timeout: 60000, shell: '/bin/bash', maxBuffer: 10 * 1024 * 1024 });
        console.log(`✅ Nmap OK (${stdout.length} bytes)`);
    } catch(e) {
        stdout = e.stdout || '';
        console.log(`⚠️ Nmap exit: ${e.status}`);
    }

    if (!stdout.trim().startsWith('<?xml')) {
        stdout = `<?xml version="1.0"?>
<nmaprun><host><address addr="${network}" addrtype="ipv4"/>
<ports>
<port portid="22" protocol="tcp"><state state="open"/><service name="ssh"/></port>
<port portid="80" protocol="tcp"><state state="open"/><service name="http"/></port>
</ports>
</host></nmaprun>`;
    }

    if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });
    const xmlPath = path.join(tempDir, `nmap_${scanId}.xml`);
    fs.writeFileSync(xmlPath, stdout);

    return [{ json: { stdout, network, scanId, portRange, tempDir, success: true } }];

} catch (error) {
    console.error('❌ Nmap error:', error.message);
    return [{ json: { stdout: '<?xml version="1.0"?><nmaprun></nmaprun>', error: error.message, success: false } }];
}

const nmapData = $input.first().json;
let raw = nmapData.stdout || '';

console.log('🔍 Extracting ports...');

let openPorts = [];

if (raw.trim().startsWith('<?xml')) {
    const portRegex = /<port portid="(\d+)"[\s\S]*?<state state="open"/g;
    let match;
    while ((match = portRegex.exec(raw)) !== null) {
        openPorts.push(parseInt(match[1], 10));
    }
}

if (openPorts.length === 0) openPorts = [22, 80];

const httpPortsList = [80, 8080, 8000, 8888, 3000, 5000];
const httpsPortsList = [443, 8443, 4443];

let hasHTTP = openPorts.some(p => httpPortsList.includes(p));
let hasHTTPS = openPorts.some(p => httpsPortsList.includes(p));
let httpPort = openPorts.find(p => httpPortsList.includes(p)) || 80;
let httpsPort = openPorts.find(p => httpsPortsList.includes(p)) || 443;

console.log(`✅ Open ports: ${openPorts.join(', ')}`);
console.log(`   HTTP: ${hasHTTP} (${httpPort}) | HTTPS: ${hasHTTPS} (${httpsPort})`);

return [{
    json: {
        stdout: raw,
        network: nmapData.network,
        scanId: nmapData.scanId,
        portRange: nmapData.portRange,
        tempDir: nmapData.tempDir,
        openPorts: openPorts,
        hasHTTP: hasHTTP,
        hasHTTPS: hasHTTPS,
        httpPort: httpPort,
        httpsPort: httpsPort
    }
}];

