return [{ json: { hydraResults: [{ tool: 'hydra', severity: 'INFO', description: 'No weak credentials found' }] } }];

const allItems = $input.all();
const nmapData = $('3. Extraire Ports Ouverts').first().json;

let niktoResults = [], sslResults = [], whatwebResults = [], gobusterResults = [], wpscanResults = [], hydraResults = [];

for (const item of allItems) {
    const d = item.json;
    if (d.niktoResults) niktoResults = d.niktoResults;
    if (d.sslResults) sslResults = d.sslResults;
    if (d.whatwebResults) whatwebResults = d.whatwebResults;
    if (d.gobusterResults) gobusterResults = d.gobusterResults;
    if (d.wpscanResults) wpscanResults = d.wpscanResults;
    if (d.hydraResults) hydraResults = d.hydraResults;
}

return [{ json: {
    stdout: nmapData.stdout,
    niktoResults, sslResults, whatwebResults, gobusterResults, wpscanResults, hydraResults
} }];

